/**
 * @summary Send a control command to a device
 */
export const getControlDeviceUrl = (deviceId: string) => {
  return `/api/devices/${deviceId}/control`;
};

export const controlDevice = async (
  deviceId: string,
  deviceControlRequest: DeviceControlRequest,
  options?: RequestInit,
): Promise<DeviceControlResult> => {
  return customFetch<DeviceControlResult>(getControlDeviceUrl(deviceId), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(deviceControlRequest),
  });
};

export const getControlDeviceMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof controlDevice>>,
    TError,
    { deviceId: string; data: BodyType<DeviceControlRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof controlDevice>>,
  TError,
  { deviceId: string; data: BodyType<DeviceControlRequest> },
  TContext
> => {
  const mutationKey = ["controlDevice"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof controlDevice>>,
    { deviceId: string; data: BodyType<DeviceControlRequest> }
  > = (props) => {
    const { deviceId, data } = props ?? {};

    return controlDevice(deviceId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ControlDeviceMutationResult = NonNullable<
  Awaited<ReturnType<typeof controlDevice>>
>;
export type ControlDeviceMutationBody = BodyType<DeviceControlRequest>;
export type ControlDeviceMutationError = ErrorType<unknown>;

/**
 * @summary Send a control command to a device
 */
export const useControlDevice = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof controlDevice>>,
    TError,
    { deviceId: string; data: BodyType<DeviceControlRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof controlDevice>>,
  TError,
  { deviceId: string; data: BodyType<DeviceControlRequest> },
  TContext
> => {
  return useMutation(getControlDeviceMutationOptions(options));
};

/**
 * @summary Get paginated event bus history
 */
export const getGetEventHistoryUrl = (params?: GetEventHistoryParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/events/history?${stringifiedParams}`
    : `/api/events/history`;
};

export const getEventHistory = async (
  params?: GetEventHistoryParams,
  options?: RequestInit,
): Promise<EventHistoryResponse> => {
  return customFetch<EventHistoryResponse>(getGetEventHistoryUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetEventHistoryQueryKey = (params?: GetEventHistoryParams) => {
  return [`/api/events/history`, ...(params ? [params] : [])] as const;
};

